+    let Some(input) = scenario.input.as_ref() else {
+        return Ok(Value::Null);
+    };
+    let server = input
+        .get("server")
+        .ok_or("mcp scenario missing server")?;
+    let name = server
+        .get("name")
+        .and_then(Value::as_str)
+        .ok_or("mcp scenario missing server.name")?;
